async function Layout({
  children,
  params,
}: {
  children: ReactNode;
  params: Promise<{lang: string}>;
}) {
  const {lang} = await params;
  const dict = hasLocale(lang) ? await getDictionary(lang) : await getDictionary("en");

  return (
    <html suppressHydrationWarning className={inter.variable} lang={lang}>
      <head>
        <script
          dangerouslySetInnerHTML={{__html: JSON.stringify(getOrganizationJsonLd())}}
          type="application/ld+json"
        />
        <script
          dangerouslySetInnerHTML={{__html: JSON.stringify(getWebSiteJsonLd())}}
          type="application/ld+json"
        />
        <script
          dangerouslySetInnerHTML={{__html: JSON.stringify(getSoftwareApplicationJsonLd())}}
          type="application/ld+json"
        />
      </head>
      <body className="flex min-h-screen flex-col font-sans">
        <NuqsAdapter>
          <NextProvider>
            <TreeContextProvider tree={source.getPageTree(lang)}>
              <CustomRootProvider dict={dict} lang={lang}>
                {children}
              </CustomRootProvider>
            </TreeContextProvider>
          </NextProvider>
        </NuqsAdapter>
        <Analytics />
      </body>
    </html>
  );
}

function injectFontLink(
  id: string,
  url: string,
  fontFamily?: string,
): HTMLLinkElement | HTMLStyleElement | null {
  if (typeof document === "undefined") return null;

  const elementId = `font-link-${id}`;
  const existingElement = document.getElementById(elementId);

  if (existingElement) {
    return existingElement as HTMLLinkElement | HTMLStyleElement;
  }

  // Check if this is a font file URL that needs @font-face generation
  if (isFontFileUrl(url)) {
    // For font files, we need the font family name to generate @font-face
    const family = fontFamily || extractFontFamilyFromUrl(url);

    if (!family) {
      console.warn("Could not determine font family for font file:", url);

      return null;
    }

    const styleElement = document.createElement("style");

    styleElement.id = elementId;
    styleElement.textContent = generateFontFaceCSS(family, url);
    document.head.appendChild(styleElement);

    return styleElement;
  }

  // For CSS stylesheet URLs, use a <link> element
  const linkElement = document.createElement("link");

  linkElement.id = elementId;
  linkElement.rel = "stylesheet";
  linkElement.href = url;
  document.head.appendChild(linkElement);

  return linkElement;
}

function ColorHeader({
  bgVariable,
  name,
  theme,
  tooltip,
}: {
  name: string;
  theme: "Light" | "Dark";
  bgVariable: string;
  tooltip?: string;
}) {
  const token = getTokenName(tooltip, bgVariable);

  return (
    <ColorTooltip content={tooltip}>
      <div
        className="flex cursor-pointer items-center justify-between rounded-xl px-4 py-3"
        style={{backgroundColor: `var(${bgVariable})`}}
        onClick={(event) => copyColorValue(event, bgVariable)}
      >
        <div className="flex flex-col">
          <span className="text-lg font-medium tracking-tight" style={contrastStyle(bgVariable)}>
            {name}
          </span>
          <span
            className="font-mono text-[10px] leading-tight opacity-60 sm:hidden"
            style={contrastStyle(bgVariable)}
          >
            {token}
          </span>
        </div>
        <span className="text-xs font-medium" style={contrastStyle(bgVariable)}>
          {theme}
        </span>
      </div>
    </ColorTooltip>
  );
}

function ColorBlock({
  bgVariable,
  cssValue,
  hasBorder,
  label,
  tooltip,
}: {
  label: string;
  bgVariable: string;
  cssValue?: string;
  hasBorder?: boolean;
  tooltip?: string;
}) {
  const bgValue = cssValue || `var(${bgVariable})`;
  const token = getTokenName(tooltip, bgVariable);

  return (
    <ColorTooltip className="block w-full" content={tooltip}>
      <div
        style={{backgroundColor: bgValue}}
        className={cn(
          "flex w-full cursor-pointer flex-col justify-center rounded-xl px-4 py-2.5",
          hasBorder && "border border-black/12 dark:border-white/12",
        )}
        onClick={(event) => copyColorValue(event, cssValue || bgVariable)}
      >
        <span className="text-sm font-medium tracking-tight" style={contrastStyle(bgVariable)}>
          {label}
        </span>
        <span
          className="font-mono text-[10px] leading-tight opacity-60 sm:hidden"
          style={contrastStyle(bgVariable)}
        >
          {token}
        </span>
      </div>
    </ColorTooltip>
  );
}

