function StackedSwatch({
  border,
  cssValue,
  label,
  tooltip,
  variable,
}: {
  label: string;
  variable: string;
  cssValue?: string;
  border?: boolean;
  tooltip?: string;
}) {
  const bgValue = cssValue || `var(${variable})`;
  const token = getTokenName(tooltip, variable);

  return (
    <ColorTooltip className="min-w-0 basis-full sm:flex-1 sm:basis-0" content={tooltip}>
      <div
        style={{backgroundColor: bgValue}}
        className={cn(
          "flex min-h-14 w-full cursor-pointer flex-col justify-center rounded-xl px-4 py-2",
          border && "border border-border",
        )}
        onClick={(event) => copyColorValue(event, cssValue || variable)}
      >
        <span className="text-sm font-medium tracking-tight" style={contrastStyle(variable)}>
          {label}
        </span>
        <span
          className="truncate font-mono text-[10px] leading-tight opacity-60 sm:hidden"
          style={contrastStyle(variable)}
        >
          {token}
        </span>
      </div>
    </ColorTooltip>
  );
}

function ComponentPreview({
  align = "center",
  className,
  description,
  hideCode = false,
  isBgSolid = false,
  locale,
  minHeight,
  name,
  ...props
}: ComponentPreviewProps) {
  const demo = getDemo(name, locale);

  if (!demo) {
    return (
      <div className={cn("my-4 rounded-md border border-red-200 bg-red-50 p-4", className)}>
        <p className="text-sm text-red-600">
          Component demo &quot;{name}&quot; not found. Make sure the demo is registered in the demos
          index.
        </p>
      </div>
    );
  }

  const Component = demo.component;

  return (
    <ComponentPreviewContainer
      align={align}
      className={className}
      description={description}
      hideCode={hideCode}
      isBgSolid={isBgSolid}
      minHeight={minHeight}
      name={name}
      {...props}
    >
      <Component />
      {!hideCode && !!demo.file && (
        <ComponentSource language="tsx" locale={locale} name={name} title={name} />
      )}
    </ComponentPreviewContainer>
  );
}

function TocThumb({containerRef}: {containerRef: RefObject<HTMLDivElement | null>}) {
  const thumbRef = useRef<HTMLDivElement>(null);
  const active = Primitive.useActiveAnchors();

  const update = useCallback(() => {
    const thumb = thumbRef.current;
    const container = containerRef.current;

    if (!thumb || !container) return;

    const [top, height] = calc(container, active);

    thumb.style.setProperty("--fd-top", `${top}px`);
    thumb.style.setProperty("--fd-height", `${height}px`);
  }, [active, containerRef]);

  useEffect(() => {
    const container = containerRef.current;

    if (!container) return;

    const observer = new ResizeObserver(update);

    observer.observe(container);
    update();

    return () => {
      observer.disconnect();
    };
  }, [update, containerRef]);

  return (
    <div
      ref={thumbRef}
      className="bg-fd-primary absolute inset-s-0 top-(--fd-top) h-(--fd-height) w-px transition-[top,height] ease-linear data-[hidden=true]:opacity-0"
      data-hidden={active.length === 0}
    />
  );
}

const VideoPlayerView = (props: VideoPlayerViewProps) => {
  const {
    autoPlay,
    className,
    controls,
    height = 300,
    playMode,
    poster,
    showQRCode = true,
    srcDark,
    srcLight,
    width,
  } = props;
  const {resolvedTheme} = useTheme();

  // Default to the light video during SSR (resolvedTheme is undefined until
  // mounted). The mismatch is acceptable because the video tag re-renders
  // immediately after hydration with the correct src.
  const videoSrc = resolvedTheme === "dark" ? srcDark : srcLight;

  return (
    <div className={cn("flex flex-col items-end gap-4", className)}>
      {!!showQRCode && <QRPreviewPopover {...pickNativeQRTarget(props)} />}

      <VideoPlayer
        autoPlay={autoPlay}
        controls={controls}
        height={height}
        playMode={playMode}
        poster={poster}
        src={videoSrc}
        width={width}
      />
    </div>
  );
};

function RelatedShowcases({className, component}: RelatedShowcasesProps) {
  const pathname = usePathname();
  const params = useParams<{lang?: string}>();
  const lang = params.lang ?? i18n.defaultLanguage;
  const showcases = getShowcasesByComponent(component);

  if (!showcases || showcases.length === 0) {
    return null;
  }

  // Encode the current pathname to use as the returnUrl parameter
  const returnUrl = encodeURIComponent(pathname);

  return (
    <div className={cn(className)}>
      <h2 className="m-0 text-xl font-semibold">Related Showcases</h2>
      <div className="not-prose -mx-2 grid grid-cols-1 gap-4 overflow-x-auto p-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4">
        {showcases.map((showcase) => (
          <ShowcaseItem
            key={showcase.name}
            className="aspect-video h-[180px] max-w-[250px] shrink-0"
            href={`/${lang}/showcase/${showcase.name}?returnUrl=${returnUrl}`}
            item={showcase}
          />
        ))}
      </div>
    </div>
  );
}

function CopyButton({
  className,
  code,
  containerRef,
  ...props
}: ComponentProps<"button"> & {
  code?: string;
  containerRef: RefObject<HTMLElement | null>;
}) {
  const [checked, onClick] = useCopyButton(() => {
    if (code) {
      void navigator.clipboard.writeText(code);

      return;
    }

    const pre = containerRef.current?.getElementsByTagName("pre").item(0);

    if (!pre) return;

    const clone = pre.cloneNode(true) as HTMLElement;

    clone.querySelectorAll(".nd-copy-ignore").forEach((node) => {
      node.replaceWith("\n");
    });

    void navigator.clipboard.writeText(clone.textContent ?? "");
  });

  return (
    <button
      aria-label={checked ? "Copied Text" : "Copy Text"}
      data-checked={checked || undefined}
      type="button"
      className={buttonVariants({
        class: cn("-mt-0.5 bg-transparent text-muted", className),
        isIconOnly: true,
        size: "sm",
        variant: "ghost",
      })}
      onClick={onClick}
      {...props}
    >
      {checked ? <Iconify icon="check" /> : <Iconify icon="copy" />}
    </button>
  );
}

async function compileAndExtractStyles(styleContent, defaultTheme, theme) {
  const compiledContent = (
    await compile(
      `
    @layer theme{${defaultTheme}${theme}}
    @layer wrapperStart{${styleContent}}
    @layer wrapperEnd
  `,
      {
        // Polyfills:
        // None = 0,
        // AtProperty = 1,
        // ColorMix = 2,
        // All = 3
        polyfills: 1, // AtProperty only, excludes ColorMix
      },
    )
  ).build([])

  const startIndex = compiledContent.indexOf("@layer wrapperStart")
  const endIndex = compiledContent.indexOf("@layer wrapperEnd")

  if (startIndex === -1 || endIndex === -1) {
    throw new Error("Failed to find wrapper layers in compiled content")
  }

  const openingBraceIndex = compiledContent.indexOf("{", startIndex)
  const closingBraceIndex = compiledContent.lastIndexOf("}", endIndex)

  if (
    openingBraceIndex === -1 ||
    closingBraceIndex === -1 ||
    openingBraceIndex >= closingBraceIndex
  ) {
    throw new Error("Invalid wrapper structure in compiled content")
  }

  return compiledContent.substring(openingBraceIndex + 1, closingBraceIndex).trim()
}

const generateResponsiveContent = (groupBreakpoints = true) => {
  if (groupBreakpoints) {
    return breakpoints
      .map((bp) => {
        const prefix = bp.match(/^\d/) ? `\\3${bp[0]}${bp.slice(1)}` : bp
        const classes = colorNames
          .flatMap((color) =>
            properties.flatMap((style) => {
              const baseClass = `.${prefix}\\:${style}-${color}{@apply ${style}-${color};}`
              const opacityClasses = (opacities.responsive || []).map(
                (opacity) =>
                  `.${prefix}\\:${style}-${color}\\/${opacity}{@apply ${style}-${color}\\/${opacity};}`,
              )
              return [baseClass, ...opacityClasses]
            }),
          )
          .join("\n")
        return `@media ${getBreakpointWidth(bp)} {\n${classes}\n}`
      })
      .join("\n\n")
  }
  return colorNames
    .flatMap((color) =>
      properties.flatMap((style) =>
        generateResponsiveVariants(style, color, opacities.responsive || []),
      ),
    )
    .join("\n")
}

function useThemeToggle() {
  const { setTheme, resolvedTheme } = useTheme()
  const { setMetaColor, metaColor } = useMetaColor()

  React.useEffect(() => {
    setMetaColor(metaColor)
  }, [metaColor, setMetaColor])

  const toggleTheme = React.useCallback(() => {
    setTheme(resolvedTheme === "dark" ? "light" : "dark")
  }, [resolvedTheme, setTheme])

  // Listen for the D key to toggle theme.
  React.useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (
        (e.key === "d" || e.key === "D") &&
        !e.metaKey &&
        !e.ctrlKey &&
        !e.altKey
      ) {
        if (
          (e.target instanceof HTMLElement && e.target.isContentEditable) ||
          e.target instanceof HTMLInputElement ||
          e.target instanceof HTMLTextAreaElement ||
          e.target instanceof HTMLSelectElement
        ) {
          return
        }

        e.preventDefault()
        toggleTheme()
      }
    }

    document.addEventListener("keydown", down)
    return () => document.removeEventListener("keydown", down)
  }, [toggleTheme])

  return { toggleTheme }
}

function ChartsNav({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const pathname = usePathname()

  return (
    <div className="relative overflow-hidden">
      <ScrollArea className="max-w-[600px] lg:max-w-none">
        <div className={cn("flex items-center", className)} {...props}>
          {links.map((link) => (
            <Link
              href={link.href}
              key={link.href}
              data-active={link.href.startsWith(pathname)}
              className={cn(
                "flex h-7 shrink-0 items-center justify-center px-4 text-center text-base font-medium text-muted-foreground transition-colors hover:text-primary data-[active=true]:text-primary"
              )}
            >
              {link.name}
            </Link>
          ))}
        </div>
        <ScrollBar orientation="horizontal" className="invisible" />
      </ScrollArea>
    </div>
  )
}
